diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9ff1e3aa5502..67b0379acf2b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -5155,6 +5155,71 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
     }
   }

+  // icmp (X /[su] C), X -> simplified comparison to zero
+  // For signed division with C > 1:
+  //   (X /s C) slt X -> X sgt 0
+  //   (X /s C) sgt X -> X slt 0
+  //   (X /s C) sle X -> X sge 0
+  //   (X /s C) sge X -> X sle 0
+  // For unsigned division with C > 1:
+  //   (X /u C) ult X -> X ugt 0 -> X != 0
+  //   (X /u C) ugt X -> X ult 0 -> false
+  //   (X /u C) ule X -> X uge 0 -> true
+  //   (X /u C) uge X -> X ule 0 -> X == 0
+  if (BO0 && BO0->getOpcode() == Instruction::SDiv && Op1 == BO0->getOperand(0)) {
+    const APInt *DivC;
+    if (match(BO0->getOperand(1), m_APInt(DivC)) && DivC->sgt(1) &&
+        ICmpInst::isSigned(Pred)) {
+      Constant *Zero = Constant::getNullValue(Op1->getType());
+      switch (Pred) {
+      case ICmpInst::ICMP_SLT:
+        return new ICmpInst(ICmpInst::ICMP_SGT, Op1, Zero);
+      case ICmpInst::ICMP_SGT:
+        return new ICmpInst(ICmpInst::ICMP_SLT, Op1, Zero);
+      case ICmpInst::ICMP_SLE:
+        return new ICmpInst(ICmpInst::ICMP_SGE, Op1, Zero);
+      case ICmpInst::ICMP_SGE:
+        return new ICmpInst(ICmpInst::ICMP_SLE, Op1, Zero);
+      case ICmpInst::ICMP_EQ:
+        return new ICmpInst(ICmpInst::ICMP_EQ, Op1, Zero);
+      case ICmpInst::ICMP_NE:
+        return new ICmpInst(ICmpInst::ICMP_NE, Op1, Zero);
+      default:
+        break;
+      }
+    }
+  }
+  if (BO0 && BO0->getOpcode() == Instruction::UDiv && Op1 == BO0->getOperand(0)) {
+    const APInt *DivC;
+    if (match(BO0->getOperand(1), m_APInt(DivC)) && DivC->ugt(1)) {
+      Constant *Zero = Constant::getNullValue(Op1->getType());
+      switch (Pred) {
+      case ICmpInst::ICMP_ULT:
+        return new ICmpInst(ICmpInst::ICMP_UGT, Op1, Zero);
+      case ICmpInst::ICMP_UGT:
+        return replaceInstUsesWith(I, ConstantInt::getFalse(I.getType()));
+      case ICmpInst::ICMP_ULE:
+        return replaceInstUsesWith(I, ConstantInt::getTrue(I.getType()));
+      case ICmpInst::ICMP_UGE:
+        return new ICmpInst(ICmpInst::ICMP_EQ, Op1, Zero);
+      // Signed predicates for unsigned division
+      case ICmpInst::ICMP_SLT:
+        return new ICmpInst(ICmpInst::ICMP_SGT, Op1, Zero);
+      case ICmpInst::ICMP_SGT:
+        return new ICmpInst(ICmpInst::ICMP_SLT, Op1, Zero);
+      case ICmpInst::ICMP_SLE:
+        return new ICmpInst(ICmpInst::ICMP_SGE, Op1, Zero);
+      case ICmpInst::ICMP_SGE:
+        return new ICmpInst(ICmpInst::ICMP_SLE, Op1, Zero);
+      case ICmpInst::ICMP_EQ:
+        return new ICmpInst(ICmpInst::ICMP_EQ, Op1, Zero);
+      case ICmpInst::ICMP_NE:
+        return new ICmpInst(ICmpInst::ICMP_NE, Op1, Zero);
+      default:
+        break;
+      }
+    }
+  }
   if (BO0 && BO1 && BO0->getOpcode() == BO1->getOpcode() &&
       (BO0->hasOneUse() || BO1->hasOneUse()) &&
       BO0->getOperand(1) == BO1->getOperand(1)) {

